#pragma alloc_text(PAGE, DriverEntry)

EVT_WDF_INTERRUPT_ENABLE  MyInterruptEnable;
EVT_WDF_INTERRUPT_DISABLE MyInterruptDisable;
EVT_WDF_INTERRUPT_ISR     MyInterruptIsr;

NTSTATUS
MyInterruptEnable(
    _In_ WDFINTERRUPT Interrupt,
    _In_ WDFDEVICE    AssociatedDevice
)
{
    // Called at DIRQL — enable hardware interrupt
    UNREFERENCED_PARAMETER(Interrupt);
    UNREFERENCED_PARAMETER(AssociatedDevice);
    WRITE_REGISTER_ULONG(&HwRegs->InterruptEnable, 1);
    return STATUS_SUCCESS;
}

NTSTATUS
MyInterruptDisable(
    _In_ WDFINTERRUPT Interrupt,
    _In_ WDFDEVICE    AssociatedDevice
)
{
    // Called at DIRQL — disable hardware interrupt
    UNREFERENCED_PARAMETER(Interrupt);
    UNREFERENCED_PARAMETER(AssociatedDevice);
    WRITE_REGISTER_ULONG(&HwRegs->InterruptEnable, 0);
    return STATUS_SUCCESS;
}

BOOLEAN
MyInterruptIsr(
    _In_ WDFINTERRUPT Interrupt,
    _In_ ULONG        MessageID
)
{
    UNREFERENCED_PARAMETER(MessageID);
    WdfInterruptQueueDpcForIsr(Interrupt);
    return TRUE;
}

